     1→// web/app/page.tsx
     2→"use client";
     3→
     4→import { useEffect } from "react";
     5→import useSWR, { mutate } from "swr";
     6→import { StatsCards } from "@/components/dashboard/stats-cards";
     7→import { ReleaseTrendChart } from "@/components/dashboard/release-trend-chart";
     8→import { UnifiedFeed } from "@/components/dashboard/unified-feed";
     9→import { DashboardEmptyState } from "@/components/dashboard/empty-state";
    10→import { DiscoverySection } from "@/components/dashboard/discovery-section";
    11→import { projects as projectsApi } from "@/lib/api/client";
    12→
    13→const SSE_BASE = process.env.NEXT_PUBLIC_API_URL || "/api/v1";
    14→
    15→export default function DashboardPage() {
    16→  const { data: projectsData, isLoading } = useSWR("projects-for-dashboard", () =>
    17→    projectsApi.list()
    18→  );
    19→
    20→  // Listen to SSE events and revalidate dashboard data on new releases
    21→  useEffect(() => {
    22→    let es: EventSource | null = null;
    23→    let retryTimer: ReturnType<typeof setTimeout> | null = null;
    24→
    25→    function connect() {
    26→      try {
    27→        es = new EventSource(`${SSE_BASE}/events`);
    28→        es.onmessage = () => {
    29→          // Revalidate all dashboard SWR keys on any event
    30→          mutate((key) => typeof key === "string" && (
    31→            key === "stats" ||
    32→            key.startsWith("trend-") ||
    33→            key === "unified-feed"
    34→          ), undefined, { revalidate: true });
    35→        };
    36→        es.onerror = () => {
    37→          es?.close();
    38→          retryTimer = setTimeout(connect, 5000);
    39→        };
    40→      } catch {
    41→        retryTimer = setTimeout(connect, 5000);
    42→      }
    43→    }
    44→
    45→    connect();
    46→    return () => {
    47→      es?.close();
    48→      if (retryTimer) clearTimeout(retryTimer);
    49→    };
    50→  }, []);
    51→
    52→  const hasProjects = !isLoading && projectsData?.data && projectsData.data.length > 0;
    53→
    54→  return (
    55→    <div className="space-y-6">
    56→      <h1
    57→        style={{
    58→          fontFamily: "var(--font-fraunces)",
    59→          fontSize: "24px",
    60→          fontWeight: 700,
    61→          color: "#111113",
    62→        }}
    63→      >
    64→        Dashboard
    65→      </h1>
    66→
    67→      <DiscoverySection />
    68→
    69→      {hasProjects ? (
    70→        <>
    71→          <StatsCards />
    72→          <div className="grid gap-4 lg:grid-cols-2">
    73→            <ReleaseTrendChart />
    74→            <UnifiedFeed />
    75→          </div>
    76→        </>
    77→      ) : isLoading ? (
    78→        <div
    79→          className="py-16 text-center"
    80→          style={{
    81→            fontFamily: "var(--font-dm-sans)",
    82→            fontSize: "13px",
    83→            color: "#6b7280",
    84→          }}
    85→        >
    86→          Loading...
    87→        </div>
    88→      ) : (
    89→        <DashboardEmptyState />
    90→      )}
    91→    </div>
    92→  );
    93→}
    94→

