     1→"use client";
     2→
     3→import { useState, Suspense } from "react";
     4→import { useSearchParams } from "next/navigation";
     5→import useSWR from "swr";
     6→import Link from "next/link";
     7→import {
     8→  releases as releasesApi,
     9→  projects as projectsApi,
    10→} from "@/lib/api/client";
    11→import { ProviderBadge } from "@/components/ui/provider-badge";
    12→import { VersionChip } from "@/components/ui/version-chip";
    13→import type { Release, Project } from "@/lib/api/types";
    14→import { ExternalLink } from "lucide-react";
    15→
    16→import { timeAgo } from "@/lib/format";
    17→
    18→const PER_PAGE = 15;
    19→
    20→function getProviderUrl(
    21→  provider: string,
    22→  repository: string,
    23→  version: string
    24→): string | null {
    25→  switch (provider) {
    26→    case "github":
    27→      return `https://github.com/${repository}/releases/tag/${version}`;
    28→    case "dockerhub":
    29→      return `https://hub.docker.com/r/${repository}/tags?name=${encodeURIComponent(version)}`;
    30→    case "ecr-public":
    31→      return `https://gallery.ecr.aws/${repository}`;
    32→    case "gitlab":
    33→      return `https://gitlab.com/${repository}/-/releases/${version}`;
    34→    default:
    35→      return null;
    36→  }
    37→}
    38→
    39→/* ------------------------------------------------------------------ */
    40→/*  Page                                                               */
    41→/* ------------------------------------------------------------------ */
    42→
    43→export default function ReleasesPage() {
    44→  return (
    45→    <Suspense>
    46→      <ReleasesPageInner />
    47→    </Suspense>
    48→  );
    49→}
    50→
    51→function ReleasesPageInner() {
    52→  const searchParams = useSearchParams();
    53→  const initialProject = searchParams.get("project") ?? "all";
    54→  const initialShowExcluded = searchParams.get("show_excluded") !== "false";
    55→  const [page, setPage] = useState(1);
    56→  const [projectFilter, setProjectFilter] = useState<string>(initialProject);
    57→  const [showExcluded, setShowExcluded] = useState(initialShowExcluded);
    58→
    59→  /* Fetch projects for the filter dropdown */
    60→  const { data: projectsData } = useSWR("projects-for-filter", async () => {
    61→    const firstPage = await projectsApi.list(1, 100);
    62→    return firstPage;
    63→  });
    64→
    65→  /* Fetch releases — scoped by project or all */
    66→  const { data: scopedData, isLoading: scopedLoading } = useSWR(
    67→    projectFilter !== "all" ? ["releases", page, projectFilter, showExcluded] : null,
    68→    () => releasesApi.listByProject(projectFilter, page, PER_PAGE, showExcluded)
    69→  );
    70→
    71→  const { data: allReleasesData, isLoading: allLoading } = useSWR(
    72→    projectFilter === "all" ? ["all-releases", page, showExcluded] : null,
    73→    () => releasesApi.list(page, PER_PAGE, showExcluded)
    74→  );
    75→
    76→  const isLoading = projectFilter !== "all" ? scopedLoading : allLoading;
    77→
    78→  /* Releases come pre-enriched with project/source metadata from the backend */
    79→  const releases: Release[] =
    80→    projectFilter !== "all"
    81→      ? scopedData?.data ?? []
    82→      : allReleasesData?.data ?? [];
    83→
    84→  /* Pagination math */
    85→  const activeData = projectFilter !== "all" ? scopedData : allReleasesData;
    86→  const total = activeData?.meta?.total ?? 0;
    87→  const totalPages = Math.max(1, Math.ceil(total / PER_PAGE));
    88→  const startRow = (page - 1) * PER_PAGE + 1;
    89→  const endRow = Math.min(page * PER_PAGE, total);
    90→
    91→  return (
    92→    <div className="space-y-6">
    93→      {/* Page title */}
    94→      <h1
    95→        style={{
    96→          fontFamily: "var(--font-fraunces)",
    97→          fontSize: "24px",
    98→          fontWeight: 700,
    99→          color: "#111113",
   100→        }}
   101→      >
   102→        Releases
   103→      </h1>
   104→
   105→      {/* Filters */}
   106→      <div className="flex items-center gap-3">
   107→        <select
   108→          value={projectFilter}
   109→          onChange={(e) => {
   110→            setProjectFilter(e.target.value);
   111→            setPage(1);
   112→          }}
   113→          className="appearance-none rounded-md bg-white px-3 py-2 pr-8 outline-none transition-shadow"
   114→          style={{
   115→            fontFamily: "var(--font-dm-sans)",
   116→            fontSize: "13px",
   117→            color: "#111113",
   118→            border: "1px solid #e8e8e5",
   119→          }}
   120→          onFocus={(e) =>
   121→            (e.currentTarget.style.boxShadow = "0 0 0 2px #e8601a40")
   122→          }
   123→          onBlur={(e) => (e.currentTarget.style.boxShadow = "none")}
   124→        >
   125→          <option value="all">All Projects</option>
   126→          {projectsData?.data.map((p: Project) => (
   127→            <option key={p.id} value={p.id}>
   128→              {p.name}
   129→            </option>
   130→          ))}
   131→        </select>
   132→
   133→        <label className="inline-flex items-center gap-2 cursor-pointer select-none">
   134→          <span style={{
   135→            fontFamily: "var(--font-dm-sans)",
   136→            fontSize: "13px",
   137→            color: "#6b7280",
   138→          }}>
   139→            Show excluded
   140→          </span>
   141→          <button
   142→            role="switch"
   143→            aria-checked={showExcluded}
   144→            onClick={() => {
   145→              const next = !showExcluded;
   146→              setShowExcluded(next);
   147→              setPage(1);
   148→              const params = new URLSearchParams(window.location.search);
   149→              if (next) params.delete("show_excluded");
   150→              else params.set("show_excluded", "false");
   151→              window.history.replaceState({}, "", `?${params.toString()}`);
   152→            }}
   153→            className="relative inline-flex h-5 w-9 items-center rounded-full transition-colors"
   154→            style={{ backgroundColor: showExcluded ? "#e8601a" : "#d1d5db" }}
   155→          >
   156→            <span
   157→              className="inline-block h-3.5 w-3.5 rounded-full bg-white transition-transform"
   158→              style={{ transform: showExcluded ? "translateX(18px)" : "translateX(3px)" }}
   159→            />
   160→          </button>
   161→        </label>
   162→      </div>
   163→
   164→      {/* Table card */}
   165→      <div
   166→        className="overflow-hidden rounded-lg bg-white"
   167→        style={{ border: "1px solid #e8e8e5" }}
   168→      >
   169→        {isLoading ? (
   170→          <div
   171→            className="py-16 text-center"
   172→            style={{
   173→              fontFamily: "var(--font-dm-sans)",
   174→              fontSize: "13px",
   175→              color: "#6b7280",
   176→            }}
   177→          >
   178→            Loading...
   179→          </div>
   180→        ) : releases.length === 0 ? (
   181→          <div className="py-16 text-center">
   182→            <p
   183→              style={{
   184→                fontFamily: "var(--font-fraunces)",
   185→                fontStyle: "italic",
   186→                fontSize: "15px",
   187→                color: "#9ca3af",
   188→              }}
   189→            >
   190→              No releases ingested yet
   191→            </p>
   192→          </div>
   193→        ) : (
   194→          <table className="w-full">
   195→            <thead>
   196→              <tr style={{ borderBottom: "1px solid #e8e8e5", backgroundColor: "#fafaf9" }}>
   197→                {["Project", "Provider", "Repository", "Version", "Released", "Age", ""].map(
   198→                  (col) => (
   199→                    <th
   200→                      key={col}
   201→                      className="px-4 py-3 text-left"
   202→                      style={{
   203→                        fontFamily: "var(--font-dm-sans)",
   204→                        fontSize: "11px",
   205→                        fontWeight: 600,
   206→                        textTransform: "uppercase" as const,
   207→                        letterSpacing: "0.08em",
   208→                        color: "#9ca3af",
   209→                      }}
   210→                    >
   211→                      {col}
   212→                    </th>
   213→                  )
   214→                )}
   215→              </tr>
   216→            </thead>
   217→            <tbody>
   218→              {releases.map((release) => (
   219→                <tr
   220→                  key={release.id}
   221→                  className={`transition-colors ${release.excluded ? '' : 'hover:bg-[#fafaf9]'}`}
   222→                  style={{
   223→                    borderBottom: "1px solid #e8e8e5",
   224→                    opacity: release.excluded ? 0.45 : 1,
   225→                  }}
   226→                >
   227→                  {/* Project */}
   228→                  <td className="px-4 py-3">
   229→                    {release.project_id ? (
   230→                      <Link
   231→                        href={`/projects/${release.project_id}`}
   232→                        className="hover:underline"
   233→                        style={{
   234→                          fontFamily: "var(--font-dm-sans)",
   235→                          fontSize: "13px",
   236→                          color: "#111113",
   237→                          fontWeight: 500,
   238→                        }}
   239→                      >
   240→                        {release.project_name ?? "\u2014"}
   241→                      </Link>
   242→                    ) : (
   243→                      <span
   244→                        style={{
   245→                          fontFamily: "var(--font-dm-sans)",
   246→                          fontSize: "13px",
   247→                          color: "#9ca3af",
   248→                        }}
   249→                      >
   250→                        {"\u2014"}
   251→                      </span>
   252→                    )}
   253→                  </td>
   254→
   255→                  {/* Provider */}
   256→                  <td className="px-4 py-3">
   257→                    {release.provider ? (
   258→                      <ProviderBadge provider={release.provider} />
   259→                    ) : (
   260→                      <span
   261→                        style={{
   262→                          fontFamily: "var(--font-dm-sans)",
   263→                          fontSize: "13px",
   264→                          color: "#9ca3af",
   265→                        }}
   266→                      >
   267→                        {"\u2014"}
   268→                      </span>
   269→                    )}
   270→                  </td>
   271→
   272→                  {/* Repository */}
   273→                  <td className="px-4 py-3">
   274→                    <span
   275→                      style={{
   276→                        fontFamily: "'JetBrains Mono', monospace",
   277→                        fontSize: "12px",
   278→                        color: "#374151",
   279→                      }}
   280→                    >
   281→                      {release.repository ?? release.source_id}
   282→                    </span>
   283→                  </td>
   284→
   285→                  {/* Version */}
   286→                  <td className="px-4 py-3">
   287→                    <Link href={`/releases/${release.id}`}>
   288→                      <VersionChip version={release.version} />
   289→                    </Link>
   290→                  </td>
   291→
   292→                  {/* Released date */}
   293→                  <td className="px-4 py-3">
   294→                    <span
   295→                      style={{
   296→                        fontFamily: "var(--font-dm-sans)",
   297→                        fontSize: "13px",
   298→                        color: "#6b7280",
   299→                      }}
   300→                    >
   301→                      {release.released_at
   302→                        ? new Date(release.released_at).toLocaleDateString()
   303→                        : "\u2014"}
   304→                    </span>
   305→                  </td>
   306→
   307→                  {/* Age */}
   308→                  <td className="px-4 py-3">
   309→                    <span
   310→                      style={{
   311→                        fontFamily: "var(--font-dm-sans)",
   312→                        fontSize: "13px",
   313→                        color: "#9ca3af",
   314→                      }}
   315→                    >
   316→                      {timeAgo(release.released_at ?? release.created_at)}
   317→                    </span>
   318→                  </td>
   319→
   320→                  {/* Provider link */}
   321→                  <td className="px-4 py-3">
   322→                    {release.provider && release.repository && (() => {
   323→                      const url = getProviderUrl(release.provider, release.repository, release.version);
   324→                      return url ? (
   325→                        <a
   326→                          href={url}
   327→                          target="_blank"
   328→                          rel="noopener noreferrer"
   329→                          className="inline-flex items-center transition-colors hover:opacity-70"
   330→                          style={{ color: "#9ca3af" }}
   331→                          title="View on provider"
   332→                        >
   333→                          <ExternalLink size={14} />
   334→                        </a>
   335→                      ) : null;
   336→                    })()}
   337→                  </td>
   338→                </tr>
   339→              ))}
   340→            </tbody>
   341→          </table>
   342→        )}
   343→      </div>
   344→
   345→      {/* Pagination */}
   346→      {total > 0 && (
   347→        <div className="flex items-center justify-between">
   348→          <span
   349→            style={{
   350→              fontFamily: "var(--font-dm-sans)",
   351→              fontSize: "13px",
   352→              color: "#9ca3af",
   353→            }}
   354→          >
   355→            {startRow}&ndash;{endRow} of {total}
   356→          </span>
   357→          <div className="flex items-center gap-2">
   358→            <button
   359→              disabled={page <= 1}
   360→              onClick={() => setPage(page - 1)}
   361→              className="rounded-md bg-white px-3 py-1.5 transition-colors hover:bg-[#fafaf9] disabled:cursor-not-allowed disabled:opacity-40"
   362→              style={{
   363→                fontFamily: "var(--font-dm-sans)",
   364→                fontSize: "13px",
   365→                color: "#374151",
   366→                border: "1px solid #e8e8e5",
   367→              }}
   368→            >
   369→              Previous
   370→            </button>
   371→            <button
