    38→/* ---------- Overflow Flow ---------- */
    39→
    40→const LINE_HEIGHT = 28; // matches leading-7 (1.75rem = 28px)
    41→const MAX_LINES = 2;
    42→const MAX_HEIGHT = LINE_HEIGHT * MAX_LINES;
    43→
    44→function FlowSection({
    45→  label,
    46→  moreHref,
    47→  children,
    48→}: {
    49→  label: string;
    50→  moreHref: string;
    51→  children: React.ReactNode;
    52→}) {
    53→  const measureRef = useRef<HTMLDivElement>(null);
    54→  const moreRef = useRef<HTMLSpanElement>(null);
    55→  const [visibleCount, setVisibleCount] = useState<number | null>(null);
    56→
    57→  const items = React.Children.toArray(children);
    58→
    59→  const measure = useCallback(() => {
    60→    const el = measureRef.current;
    61→    if (!el) return;
    62→    const nodes = el.children;
    63→    const itemNodeCount = nodes.length - 2; // exclude label (first) and hidden "more…" span (last)
    64→    // Check if everything fits without overflow
    65→    if (el.scrollHeight <= MAX_HEIGHT + 4) {
    66→      setVisibleCount(items.length);
    67→      return;
    68→    }
    69→    // Measure actual "more…" link width
    70→    const moreWidth = moreRef.current ? moreRef.current.offsetWidth + 8 : 52;
    71→    const containerWidth = el.offsetWidth;
    72→    // First pass: find all items that fit within MAX_HEIGHT (2 lines)
    73→    let lastFitting = 0;
    74→    for (let i = 1; i <= itemNodeCount; i++) {
    75→      const node = nodes[i] as HTMLElement;
    76→      if (node.offsetTop + node.offsetHeight > MAX_HEIGHT) break;
    77→      lastFitting = i;
    78→    }
    79→    // Second pass: walk backward from lastFitting until "more…" fits after the item
    80→    let count = lastFitting;
    81→    while (count > 1) {
    82→      const node = nodes[count] as HTMLElement;
    83→      const nodeBottom = node.offsetTop + node.offsetHeight;
    84→      // If this item is on line 1, "more…" can always wrap to line 2 — we're fine
    85→      if (nodeBottom <= LINE_HEIGHT) break;
    86→      // Item is on line 2 — check if "more…" fits after it on the same line
    87→      const nodeRight = node.offsetLeft + node.offsetWidth;
    88→      if (nodeRight + moreWidth <= containerWidth) break;
    89→      count--;
    90→    }
    91→    setVisibleCount(Math.max(1, count));
    92→  }, [items.length]);
    93→
    94→  useEffect(() => {
    95→    const raf = requestAnimationFrame(measure);
    96→    const obs = new ResizeObserver(measure);
    97→    if (measureRef.current) obs.observe(measureRef.current);
    98→    return () => {
    99→      cancelAnimationFrame(raf);
   100→      obs.disconnect();
   101→    };
   102→  }, [measure, items.length]);
   103→
   104→  const hasOverflow = visibleCount !== null && visibleCount < items.length;
   105→  const displayed = visibleCount !== null ? items.slice(0, visibleCount) : items;
   106→
   107→  return (
   108→    <div className="relative">
   109→      {/* Hidden measurer — renders all items to find cutoff */}
   110→      <div
   111→        ref={measureRef}
   112→        className="text-[13px] leading-7"
   113→        style={{ position: "absolute", visibility: "hidden", top: 0, left: 0, right: 0, pointerEvents: "none" }}
   114→        aria-hidden="true"
   115→      >
   116→        <span className="text-[11px] font-medium uppercase tracking-[0.08em] mr-1.5">
   117→          {label}:
   118→        </span>
   119→        {items}
   120→        {/* Hidden "more…" to measure its actual width */}
   121→        <span ref={moreRef} className="inline-flex items-baseline text-[12px] font-medium whitespace-nowrap">
   122→          more…
   123→        </span>
   124→      </div>
   125→      {/* Visible section */}
   126→      <div className="text-[13px] leading-7">
   127→        <span
   128→          className="text-[11px] font-medium uppercase tracking-[0.08em] mr-1.5"
   129→          style={{ color: "#9ca3af", fontFamily: "var(--font-dm-sans)" }}
   130→        >
   131→          {label}:
   132→        </span>
   133→        {displayed}
   134→        {hasOverflow && (
   135→          <Link
   136→            href={moreHref}
   137→            className="inline-flex items-baseline text-[12px] font-medium hover:underline whitespace-nowrap"
   138→            style={{ color: "#e8601a" }}
   139→          >
   140→            more…
   141→          </Link>
   142→        )}
   143→      </div>
   144→    </div>
   145→  );
   146→}
