     7→
     8→	"github.com/sentioxyz/changelogue/internal/models"
     9→)
    10→
    11→// SubscriptionsStore defines the persistence operations for subscriptions.
    12→type SubscriptionsStore interface {
    13→	ListSubscriptions(ctx context.Context, page, perPage int) ([]models.Subscription, int, error)
    14→	CreateSubscription(ctx context.Context, sub *models.Subscription) error
    15→	CreateSubscriptionBatch(ctx context.Context, subs []models.Subscription) ([]models.Subscription, error)
    16→	GetSubscription(ctx context.Context, id string) (*models.Subscription, error)
    17→	UpdateSubscription(ctx context.Context, id string, sub *models.Subscription) error
    18→	DeleteSubscription(ctx context.Context, id string) error
    19→	DeleteSubscriptionBatch(ctx context.Context, ids []string) error
    20→}
    21→
    22→// SubscriptionsHandler implements HTTP handlers for the /subscriptions resource.
    23→type SubscriptionsHandler struct {
    24→	store SubscriptionsStore
    25→}
    26→
    27→// NewSubscriptionsHandler returns a new SubscriptionsHandler.
    28→func NewSubscriptionsHandler(store SubscriptionsStore) *SubscriptionsHandler {
    29→	return &SubscriptionsHandler{store: store}
    30→}
    31→
    32→// List handles GET /subscriptions — returns a paginated list of subscriptions.
    33→func (h *SubscriptionsHandler) List(w http.ResponseWriter, r *http.Request) {
    34→	page, perPage := ParsePagination(r)
    35→	subs, total, err := h.store.ListSubscriptions(r.Context(), page, perPage)
    36→	if err != nil {
    37→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to list subscriptions")
    38→		return
    39→	}
    40→	if subs == nil {
    41→		subs = []models.Subscription{}
    42→	}
    43→	RespondList(w, r, http.StatusOK, subs, page, perPage, total)
    44→}
    45→
    46→// Create handles POST /subscriptions — creates a new subscription.
    47→func (h *SubscriptionsHandler) Create(w http.ResponseWriter, r *http.Request) {
    48→	var sub models.Subscription
    49→	if err := DecodeJSON(r, &sub); err != nil {
    50→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid JSON body")
    51→		return
    52→	}
    53→	sub.Type = strings.TrimSpace(sub.Type)
    54→	sub.ChannelID = strings.TrimSpace(sub.ChannelID)
    55→	// Validate type is source_release or semantic_release.
    56→	if sub.Type != "source_release" && sub.Type != "semantic_release" {
    57→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "type must be 'source_release' or 'semantic_release'")
    58→		return
    59→	}
    60→	if sub.ChannelID == "" {
    61→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "channel_id is required")
    62→		return
