    18→// NotifyStore is the data access interface required by the notification worker.
    19→type NotifyStore interface {
    20→	GetRelease(ctx context.Context, id string) (*models.Release, error)
    21→	GetSource(ctx context.Context, id string) (*models.Source, error)
    22→	ListSourceSubscriptions(ctx context.Context, sourceID string) ([]models.Subscription, error)
    23→	GetChannel(ctx context.Context, id string) (*models.NotificationChannel, error)
    24→	GetProject(ctx context.Context, id string) (*models.Project, error)
    25→	GetPreviousRelease(ctx context.Context, sourceID string, beforeVersion string) (*models.Release, error)
    26→	EnqueueAgentRun(ctx context.Context, projectID, trigger, version string) error
    27→}
    28→
    29→// NotifyWorker is a River worker that processes NotifyJobArgs.
    30→// It looks up the release, finds all source-level subscriptions, resolves
    31→// the notification channel for each, and dispatches via the appropriate sender.
    32→// After sending notifications, it checks the project's agent rules and
    33→// auto-triggers an agent run if the version criteria are met.
    34→type NotifyWorker struct {
    35→	river.WorkerDefaults[queue.NotifyJobArgs]
    36→	store     NotifyStore
    37→	senders   map[string]Sender
    38→	publicURL string // base URL for internal Changelogue links (e.g. "https://changelogue.example.com")
    39→}
    40→
    41→// NewSenders returns the default sender map for all notification channel types.
    42→func NewSenders() map[string]Sender {
    43→	return map[string]Sender{
    44→		"webhook": &WebhookSender{Client: &http.Client{Timeout: 10 * time.Second}},
    45→		"slack":   &SlackSender{Client: &http.Client{Timeout: 10 * time.Second}},
    46→		"discord": &DiscordSender{Client: &http.Client{Timeout: 10 * time.Second}},
    47→		"email":   &EmailSender{},
    48→	}
    49→}
    50→
    51→// NewNotifyWorker creates a NotifyWorker with default senders for webhook, Slack, and Discord.
    52→func NewNotifyWorker(store NotifyStore, publicURL string) *NotifyWorker {
    53→	return &NotifyWorker{
    54→		store:     store,
    55→		senders:   NewSenders(),
    56→		publicURL: strings.TrimRight(publicURL, "/"),
    57→	}
    58→}
    59→
    60→// VersionPassesFilter returns true if the version string passes the source's
    61→// include/exclude regex filters. When both are nil the version always passes.
    62→func VersionPassesFilter(version string, include, exclude *string) bool {
    63→	if include != nil && *include != "" {
    64→		matched, err := regexp.MatchString(*include, version)
    65→		if err != nil || !matched {
    66→			return false
    67→		}
    68→	}
    69→	if exclude != nil && *exclude != "" {
    70→		matched, err := regexp.MatchString(*exclude, version)
    71→		if err != nil || matched {
    72→			return false
    73→		}
    74→	}
    75→	return true
    76→}
    77→
    78→// Work processes a notify job: fetches the release, resolves subscriptions,
    79→// sends notifications to all matching channels, and checks agent rules to
    80→// auto-trigger agent runs when version criteria are met.
    81→func (w *NotifyWorker) Work(ctx context.Context, job *river.Job[queue.NotifyJobArgs]) error {
    82→	release, err := w.store.GetRelease(ctx, job.Args.ReleaseID)
    83→	if err != nil {
    84→		return fmt.Errorf("get release: %w", err)
    85→	}
    86→
    87→	// Check source version filters — skip entirely if filtered out.
    88→	source, err := w.store.GetSource(ctx, job.Args.SourceID)
    89→	if err != nil {
    90→		return fmt.Errorf("get source: %w", err)
    91→	}
    92→	if !VersionPassesFilter(release.Version, source.VersionFilterInclude, source.VersionFilterExclude) {
    93→		slog.Debug("release filtered by version filter", "version", release.Version, "source_id", job.Args.SourceID)
    94→		return nil
    95→	}
    96→
    97→	// Check exclude_prereleases — skip if source excludes prereleases and this is one.
    98→	if source.ExcludePrereleases {
    99→		var rawData map[string]interface{}
   100→		if err := json.Unmarshal(release.RawData, &rawData); err == nil {
   101→			if prerelease, _ := rawData["prerelease"].(string); prerelease == "true" {
   102→				slog.Debug("release filtered by exclude_prereleases", "version", release.Version, "source_id", job.Args.SourceID)
   103→				return nil
   104→			}
   105→		}
   106→	}
   107→
   108→	subs, err := w.store.ListSourceSubscriptions(ctx, job.Args.SourceID)
   109→	if err != nil {
   110→		return fmt.Errorf("list subscriptions: %w", err)
   111→	}
   112→
   113→	for _, sub := range subs {
   114→		ch, err := w.store.GetChannel(ctx, sub.ChannelID)
   115→		if err != nil {
   116→			slog.Error("get channel failed", "channel_id", sub.ChannelID, "err", err)
   117→			continue
   118→		}
   119→
   120→		sender, ok := w.senders[ch.Type]
   121→		if !ok {
   122→			slog.Warn("unknown channel type", "type", ch.Type)
   123→			continue
   124→		}
   125→
   126→		// Build title with project name if available.
   127→		title := release.Version
   128→		if release.ProjectName != "" {
   129→			title = release.ProjectName
   130→		}
   131→
   132→		msg := Notification{
   133→			Title:       title,
   134→			Body:        string(release.RawData),
   135→			Version:     release.Version,
   136→			ProjectName: release.ProjectName,
   137→			Provider:    release.Provider,
   138→			Repository:  release.Repository,
   139→			SourceURL:   ProviderURL(release.Provider, release.Repository, release.Version),
   140→		}
   141→		if w.publicURL != "" {
   142→			msg.ReleaseURL = fmt.Sprintf("%s/releases/%s", w.publicURL, release.ID)
   143→		}
   144→
   145→		if err := sender.Send(ctx, ch, msg); err != nil {
   146→			slog.Error("send notification failed", "channel", ch.Name, "err", err)
   147→		}
   148→	}
   149→
   150→	// Check agent rules and auto-trigger if criteria are met.
   151→	w.checkAgentRules(ctx, release, source)
   152→
   153→	return nil
   154→}
   155→
   156→// checkAgentRules evaluates the project's agent rules against the new release
   157→// and the previous release for this source. If any rule matches, an agent run
   158→// is enqueued. Errors are logged but do not fail the job — notification delivery
   159→// is the primary responsibility.
   160→func (w *NotifyWorker) checkAgentRules(ctx context.Context, release *models.Release, source *models.Source) {
   161→	project, err := w.store.GetProject(ctx, source.ProjectID)
   162→	if err != nil {
   163→		slog.Error("get project for agent rules", "project_id", source.ProjectID, "err", err)
   164→		return
   165→	}
   166→
   167→	// Parse the project's agent_rules JSON.
   168→	var rules models.AgentRules
   169→	if len(project.AgentRules) > 0 {
   170→		if err := json.Unmarshal(project.AgentRules, &rules); err != nil {
   171→			slog.Error("unmarshal agent rules", "project_id", project.ID, "err", err)
   172→			return
   173→		}
   174→	}
   175→
   176→	// Determine the previous version for comparison.
   177→	var previousVersion string
   178→	prev, err := w.store.GetPreviousRelease(ctx, source.ID, release.Version)
   179→	if err != nil {
   180→		slog.Error("get previous release for agent rules", "source_id", source.ID, "err", err)
   181→		return
   182→	}
   183→	if prev != nil {
   184→		previousVersion = prev.Version
   185→	}
   186→
   187→	if CheckAgentRules(&rules, release.Version, previousVersion) {
   188→		trigger := fmt.Sprintf("auto:version:%s", release.Version)
   189→		if err := w.store.EnqueueAgentRun(ctx, source.ProjectID, trigger, release.Version); err != nil {
   190→			slog.Error("enqueue agent run", "project_id", source.ProjectID, "err", err)
   191→		} else {
   192→			slog.Info("agent run triggered by version rules",
   193→				"project_id", source.ProjectID,
   194→				"version", release.Version,
   195→				"previous_version", previousVersion,
   196→			)
   197→		}
   198→	}
   199→}
