   206→func (s *EmailSender) buildEmailData(msg Notification) emailData {
   207→	data := emailData{
   208→		SourceURL:     msg.SourceURL,
   209→		ReleaseURL:    msg.ReleaseURL,
   210→		ProviderLabel: ProviderLabel(msg.Provider),
   211→		UrgencyColor:  "#2563EB", // default blue
   212→	}
   213→
   214→	// Footer
   215→	if msg.Provider != "" && msg.Repository != "" {
   216→		data.FooterText = fmt.Sprintf("%s · %s", ProviderLabel(msg.Provider), msg.Repository)
   217→	}
   218→
   219→	// Try semantic report first.
   220→	var report models.SemanticReport
   221→	if err := json.Unmarshal([]byte(msg.Body), &report); err == nil && report.Subject != "" {
   222→		urgency := report.Urgency
   223→		if urgency == "" {
   224→			urgency = report.RiskLevel
   225→		}
   226→		urgencyReason := report.UrgencyReason
   227→		if urgencyReason == "" {
   228→			urgencyReason = report.RiskReason
   229→		}
   230→
   231→		data.Subject = fmt.Sprintf("%s %s", msg.Title, msg.Version)
   232→		data.UrgencyColor = urgencyColor(urgency)
   233→		if urgency != "" {
   234→			data.UrgencyBadge = fmt.Sprintf("%s %s Urgency", urgencyEmoji(urgency), urgency)
   235→		}
   236→		upperUrgency := strings.ToUpper(strings.TrimSpace(urgency))
   237→		if (upperUrgency == "CRITICAL" || upperUrgency == "HIGH") && urgencyReason != "" {
   238→			data.UrgencyReason = urgencyReason
   239→		}
   240→		summary := report.ChangelogSummary
   241→		if summary == "" {
   242→			summary = report.Summary
   243→		}
   244→		data.Summary = summary
   245→		if len(report.DownloadCommands) > 0 {
   246→			data.DownloadCommand = report.DownloadCommands[0]
   247→		}
   248→		return data
   249→	}
   250→
   251→	// Fallback: source-level release.
   252→	data.Subject = fmt.Sprintf("%s %s", msg.Title, msg.Version)
   253→	if fields, ok := parseRawBody(msg.Body); ok && fields.Changelog != "" {
   254→		data.Changelog = markdownToASCII(fields.Changelog)
   255→	}
   256→	return data
   257→}
   258→
   259→func (s *EmailSender) buildPlainText(data emailData) string {
   260→	var b strings.Builder
   261→	b.WriteString(data.Subject + "\n")
   262→	b.WriteString(strings.Repeat("=", len(data.Subject)) + "\n\n")
   263→
   264→	if data.UrgencyBadge != "" {
   265→		b.WriteString(data.UrgencyBadge + "\n")
   266→		if data.UrgencyReason != "" {
   267→			b.WriteString(data.UrgencyReason + "\n")
   268→		}
   269→		b.WriteString("\n")
   270→	}
   271→
   272→	if data.Summary != "" {
   273→		b.WriteString(data.Summary + "\n\n")
   274→	}
   275→
   276→	if data.Changelog != "" {
   277→		b.WriteString(data.Changelog + "\n\n")
   278→	}
   279→
   280→	if data.DownloadCommand != "" {
   281→		b.WriteString("  " + data.DownloadCommand + "\n\n")
   282→	}
   283→
   284→	if data.SourceURL != "" {
   285→		b.WriteString("View on " + data.ProviderLabel + ": " + data.SourceURL + "\n")
   286→	}
   287→	if data.ReleaseURL != "" {
   288→		b.WriteString("View in Changelogue: " + data.ReleaseURL + "\n")
   289→	}
   290→
   291→	if data.FooterText != "" {
   292→		b.WriteString("\n---\n" + data.FooterText + "\n")
   293→	}
   294→
   295→	return b.String()
   296→}
