    67→// buildSemanticBlocks builds compact Slack Block Kit blocks from a SemanticReport.
    68→// For Critical/High urgency, includes the urgency reason. For Low/Medium, omits it.
    69→func buildSemanticBlocks(title string, report *models.SemanticReport, msg Notification) []slackBlock {
    70→	// Resolve urgency from new field or backward-compat risk_level
    71→	urgency := report.Urgency
    72→	if urgency == "" {
    73→		urgency = report.RiskLevel
    74→	}
    75→	urgencyReason := report.UrgencyReason
    76→	if urgencyReason == "" {
    77→		urgencyReason = report.RiskReason
    78→	}
    79→
    80→	// Header: "ProjectName vX.Y.Z — 🟢 Low Urgency"
    81→	headerText := title
    82→	if urgency != "" {
    83→		headerText = fmt.Sprintf("%s — %s %s Urgency", title, urgencyEmoji(urgency), urgency)
    84→	}
    85→	// Slack header max is 150 chars
    86→	if len(headerText) > 150 {
    87→		headerText = headerText[:147] + "..."
    88→	}
    89→
    90→	blocks := []slackBlock{
    91→		{Type: "header", Text: &slackText{Type: "plain_text", Text: headerText}},
    92→	}
    93→
    94→	// Urgency reason (only for Critical/High)
    95→	upperUrgency := strings.ToUpper(strings.TrimSpace(urgency))
    96→	if (upperUrgency == "CRITICAL" || upperUrgency == "HIGH") && urgencyReason != "" {
    97→		blocks = append(blocks, slackBlock{
    98→			Type: "section",
    99→			Text: &slackText{Type: "mrkdwn", Text: fmt.Sprintf("⚠️ %s", urgencyReason)},
   100→		})
   101→	}
   102→
   103→	// Changelog summary
   104→	summary := report.ChangelogSummary
   105→	if summary == "" {
   106→		summary = report.Summary
   107→	}
   108→	if summary != "" {
   109→		blocks = append(blocks, slackBlock{
   110→			Type: "section",
   111→			Text: &slackText{Type: "mrkdwn", Text: summary},
   112→		})
   113→	}
   114→
   115→	// First download command only
   116→	if len(report.DownloadCommands) > 0 {
   117→		blocks = append(blocks, slackBlock{
   118→			Type: "section",
   119→			Text: &slackText{Type: "mrkdwn", Text: fmt.Sprintf("`%s`", report.DownloadCommands[0])},
   120→		})
   121→	}
   122→
   123→	// Footer context with source info and links
   124→	var footerParts []string
   125→	if msg.Provider != "" && msg.Repository != "" {
   126→		footerParts = append(footerParts, fmt.Sprintf("%s · %s", ProviderLabel(msg.Provider), msg.Repository))
   127→	}
   128→	if msg.SourceURL != "" {
   129→		footerParts = append(footerParts, fmt.Sprintf("<%s|View on %s>", msg.SourceURL, ProviderLabel(msg.Provider)))
   130→	}
   131→	if msg.ReleaseURL != "" {
   132→		footerParts = append(footerParts, fmt.Sprintf("<%s|View in Changelogue>", msg.ReleaseURL))
   133→	}
   134→	if len(footerParts) > 0 {
   135→		blocks = append(blocks, slackBlock{
   136→			Type: "context",
   137→			Elements: []slackText{
   138→				{Type: "mrkdwn", Text: strings.Join(footerParts, "  |  ")},
   139→			},
   140→		})
   141→	}
   142→
   143→	return blocks
   144→}
